1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	export interface Damage {
21	  itemType: string;
22	  amount: number;
23	}
24	
25	export interface Incident {
26	  cause: string;
27	  damages: Damage[];
28	}
29	
30	export interface ClaimResult {
31	  payout: number;
32	  remainingCap: number;
33	}
34	
35	// Runes and moonstones are "components" — a distinct pricing tier that shares
36	// one base premium (and, later, block/alike rules). Naming the shared value
37	// makes the equality intentional rather than a coincidence two entries happen
38	// to share.
39	const COMPONENT_BASE_PREMIUM = 25;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	// A "building block" of exactly this many alike components is offered at a
42	// special block premium instead of the per-component price.
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	
46	const BASE_PREMIUMS: Record<string, number> = {
47	  sword: 100,
48	  amulet: 60,
49	  staff: 80,
50	  potion: 40,
51	  rune: COMPONENT_BASE_PREMIUM,
52	  moonstone: COMPONENT_BASE_PREMIUM,
53	};
54	const PROCESSING_FEE = 5;
55	
56	// Surcharges are expressed as integer percentages and applied as
57	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
58	// such as `100 * 1.1 === 100.00000000000001`).
59	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
60	const CURSE_SURCHARGE_PERCENT = 50;
61	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
62	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
63	const LOYALTY_DISCOUNT_PERCENT = 20;
64	const LOYALTY_MIN_YEARS = 2;
65	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
66	const FIRST_CONTRACT_INDEX = 0;
67	const DEDUCTIBLE = 100;
68	const HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL = 8;
69	const HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT = 50;
70	
71	// Sum a numeric measure over a list. Centralises the
72	// `reduce((total, x) => total + f(x), 0)` shape shared by every per-item /
73	// per-damage total in this module, so each caller states only *what* it sums.
74	const sumBy = <T>(items: T[], measure: (item: T) => number): number =>
75	  items.reduce((total, item) => total + measure(item), 0);
76	
77	const percentOf = (amount: number, percent: number): number =>
78	  (amount * percent) / 100;
79	
80	// A surcharge that applies only when a condition holds, expressed as a
81	// percentage of some base amount (and 0 otherwise).
82	const conditionalPercent = (
83	  applies: boolean,
84	  amount: number,
85	  percent: number,
86	): number => (applies ? percentOf(amount, percent) : 0);
87	
88	// The base premium for a given item type, with unknown types priced at 0.
89	// This is the single point that reads BASE_PREMIUMS, so both per-item and
90	// per-group pricing share one definition of "the base price of a type".
91	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
92	
93	// An item's effective enchantment level, with an absent enchantment treated as
94	// 0. Centralising the default keeps "unenchanted counts as level 0" in one
95	// place for every threshold check (quote surcharge at 5, claim 50% at 8).
96	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
97	
98	// A single item's base premium. Block pricing is a group-level concern handled
99	// separately in sumBasePremiums, so a plain per-type lookup suffices here.
100	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
101	
102	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
103	
104	// Reject the first element that fails a validity predicate. Centralises the
105	// "scan a list, throw on the first invalid element" shape shared by the quote
106	// and claim guards, so each caller states only *what* is valid and *why* an
107	// invalid element is rejected.
108	const assertEach = <T>(
109	  items: T[],
110	  isValid: (item: T) => boolean,
111	  message: (item: T) => string,
112	): void => {
113	  for (const item of items) {
114	    if (!isValid(item)) {
115	      throw new Error(message(item));
116	    }
117	  }
118	};
119	
120	// A quote can only price item types it has a base premium for, so an unknown
121	// type is rejected up front rather than silently priced at 0. Named so the
122	// quote body reads "reject unknown types, then price" instead of spelling the
123	// scan out inline.
124	const assertKnownItemTypes = (items: Item[]): void =>
125	  assertEach(
126	    items,
127	    (item) => isKnownItemType(item.type),
128	    (item) => `unknown item type: ${item.type}`,
129	  );
130	
131	// Item-specific surcharges, each a percentage of the item's own base premium:
132	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
133	// stack when both apply.
134	const itemSurcharge = (item: Item): number => {
135	  const base = itemBasePremium(item);
136	  const curse = conditionalPercent(
137	    item.cursed ?? false,
138	    base,
139	    CURSE_SURCHARGE_PERCENT,
140	  );
141	  const highEnchantment = conditionalPercent(
142	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_MIN_LEVEL,
143	    base,
144	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
145	  );
146	  return curse + highEnchantment;
147	};
148	
149	const sumItemSurcharges = (items: Item[]): number =>
150	  sumBy(items, itemSurcharge);
151	
152	const countByType = (items: Item[]): Map<string, number> => {
153	  const counts = new Map<string, number>();
154	  for (const item of items) {
155	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
156	  }
157	  return counts;
158	};
159	
160	const componentGroupPremium = (count: number): number =>
161	  count === COMPONENT_BLOCK_SIZE
162	    ? COMPONENT_BLOCK_PREMIUM
163	    : count * COMPONENT_BASE_PREMIUM;
164	
165	const typeGroupPremium = (type: string, count: number): number =>
166	  COMPONENT_TYPES.has(type)
167	    ? componentGroupPremium(count)
168	    : count * basePremiumForType(type);
169	
170	const sumBasePremiums = (items: Item[]): number =>
171	  sumBy([...countByType(items)], ([type, count]) =>
172	    typeGroupPremium(type, count),
173	  );
174	
175	// Policy-wide modifiers scale with the whole policy's base premium.
176	// First-insurance is a surcharge every new policy pays; the loyalty discount
177	// rewards customers at or past the loyalty threshold.
178	const firstInsuranceSurcharge = (policyBase: number): number =>
179	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
180	
181	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
182	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
183	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
184	    : 0;
185	
186	// Every contract after the customer's first quote in the scenario is a
187	// follow-up contract and earns a discount.
188	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
189	  quoteIndex > FIRST_CONTRACT_INDEX
190	    ? percentOf(policyBase, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT)
191	    : 0;
192	
193	// Net signed adjustment that policy-wide modifiers make to the policy base:
194	// the first-insurance surcharge adds, the loyalty and follow-up discounts
195	// subtract. Grouping them keeps the quote formula at "base + item surcharges
196	// + policy-wide adjustments + fee".
197	const policyAdjustments = (
198	  customer: Customer,
199	  quoteIndex: number,
200	  policyBase: number,
201	): number =>
202	  firstInsuranceSurcharge(policyBase) -
203	  loyaltyDiscount(customer, policyBase) -
204	  followUpDiscount(quoteIndex, policyBase);
205	
206	export const quote = (
207	  customer: Customer,
208	  step: QuoteStep,
209	  quoteIndex: number,
210	): QuoteResult => {
211	  assertKnownItemTypes(step.items);
212	  const policyBase = sumBasePremiums(step.items);
213	  const premium = Math.ceil(
214	    policyBase +
215	      sumItemSurcharges(step.items) +
216	      policyAdjustments(customer, quoteIndex, policyBase) +
217	      PROCESSING_FEE,
218	  );
219	  return { premium };
220	};
221	
222	// Reimbursement for one damage before the deductible. A highly-enchanted item
223	// (level >= 8) is reimbursed at 50% of the damage; otherwise in full.
224	const reimbursement = (item: Item, damage: Damage): number =>
225	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL
226	    ? percentOf(damage.amount, HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT)
227	    : damage.amount;
228	
229	// Payout for one damage: the reimbursement minus the deductible, never below 0.
230	const damagePayout = (item: Item, damage: Damage): number =>
231	  Math.max(0, reimbursement(item, damage) - DEDUCTIBLE);
232	
233	// Removes and returns the first policy item insuring this damage's type. Each
234	// damage consumes a distinct insured item, so a claim with more damages of a
235	// type than the policy covers leaves a damage unmatched — which is rejected.
236	const takeInsuredItem = (available: Item[], damage: Damage): Item => {
237	  const index = available.findIndex((item) => item.type === damage.itemType);
238	  if (index < 0) {
239	    throw new Error(
240	      `damage references item not covered by policy: ${damage.itemType}`,
241	    );
242	  }
243	  return available.splice(index, 1)[0];
244	};
245	
246	const assertNonNegativeDamages = (damages: Damage[]): void =>
247	  assertEach(
248	    damages,
249	    (damage) => damage.amount >= 0,
250	    (damage) => `damage amount must not be negative: ${damage.amount}`,
251	  );
252	
253	export const claim = (
254	  policyItems: Item[],
255	  incident: Incident,
256	  remainingCap: number,
257	): ClaimResult => {
258	  assertNonNegativeDamages(incident.damages);
259	  // Each damage consumes a distinct insured item from `available`, so the loop
260	  // is explicit: takeInsuredItem mutates `available` as it goes, and a plain
261	  // accumulator makes that consume-as-you-go ordering visible (rather than
262	  // hiding the side effect inside a pure-looking sumBy).
263	  const available = [...policyItems];
264	  let requested = 0;
265	  for (const damage of incident.damages) {
266	    requested += damagePayout(takeInsuredItem(available, damage), damage);
267	  }
268	  const payout = Math.floor(Math.min(requested, remainingCap));
269	  return { payout, remainingCap: remainingCap - payout };
270	};
